import { Injectable } from "@angular/core";
import { EnvService } from "../env.service";
import { HttpClient, HttpHeaders } from "@angular/common/http";
import {
  UploadTransactionFileRequest,
  UploadTransactionFileResponse,
} from "src/app/views/Models/Overdraft/OdTransaction/UploadTransactionFile";
import { HttpParams } from "@capacitor/core";

@Injectable({
  providedIn: "root",
})
export class OdTransactionService {
  constructor(private http: HttpClient, private env: EnvService) {}

  uploadTransactionFile(request: UploadTransactionFileRequest) {
    const formData = new FormData();
    formData.append("FileName", request.fileName);
    formData.append("FileData", request.fileData);
    formData.append("FileType", request.fileType);

    const httpParams :HttpParams ={
      responseType: "text/csv"
    }


    return this.http.post(
      `${this.env.API_URL}api/Transaction/UploadFile`,
      formData,
      httpParams
    );
  }
}
