import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { AlertController } from "@ionic/angular";
import { BehaviorSubject } from "rxjs";
import { AlertService } from "src/app/core/services/alert.service";
import { ImportingService } from "src/app/core/services/importing.service";
import { OdTransactionService } from "src/app/core/services/overdraft/od-transaction.service";
import {
  OverDraftTransactionFileType,
  UploadTransactionFileRequest,
} from "src/app/views/Models/Overdraft/OdTransaction/UploadTransactionFile";
import { saveAs } from "file-saver";

@Component({
  selector: "app-upload-transaction-file",
  templateUrl: "./upload-transaction-file.page.html",
  styleUrls: ["./upload-transaction-file.page.scss"],
})
export class UploadTransactionFilePage implements OnInit {
  constructor(
    private alertService: AlertService,
    private importingService: ImportingService,
    private OdTransactionService: OdTransactionService,
    private alertController: AlertController
  ) {}

  showLoader: boolean = false;

  private documentType = new BehaviorSubject<string | null>(null);
  public documentType$ = this.documentType.asObservable();

  documentTypeList: { id: string; name: string }[] = [
    { id: "1", name: "سحب" },
    { id: "2", name: "ايداع" },
  ];

  ngOnInit() {}

  onDocumentTypeChange(event: string) {
    this.documentType.next(event);
  }

  async uploadingExcelFile() {
    try {
      this.showLoader = true;
      const result = await this.importingService.uploadExcelFile();

      if (!result.isSuccess) {
        this.alertService.showAlertError(result.errorMessage, false);
        return;
      }

      let request: UploadTransactionFileRequest = null;

      result.formData.forEach((file) => {
        if (file instanceof File) {
          request = {
            fileData: file,
            fileName: file.name,
            fileType:
              this.documentType.value === "1"
                ? OverDraftTransactionFileType.WithDraw
                : OverDraftTransactionFileType.Deposit,
          };
        }
      });

      if (!request) return;

      const dbResult = await this.OdTransactionService.uploadTransactionFile(
        request
      ).toPromise();

      if (dbResult === null) {
        await this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", false);
      } else {
        await this.downloadingErrorFile(dbResult);
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async downloadingErrorFile(file: any) {
    let blob = new Blob([file], { type: "text/csv" });
    let fileName = `response-${new Date().toISOString().split("T")[0]}`;
    await saveAs(blob, fileName);
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
