import { Injectable } from "@angular/core";
import * as XLSX from "xlsx";

interface UploadExcelFile {
  isSuccess: boolean;
  errorMessage: string | null;
  fileName: string | null;
  result: any[] | null;
  formData?: FormData;
}

@Injectable({
  providedIn: "root",
})
export class ImportingService {
  constructor() {}

  private readonly allowedExtensions = ['xlsx', 'xls'];
  private readonly allowedMimeTypes = [
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'application/vnd.ms-excel',
  ];


  public async uploadExcelFile(): Promise<UploadExcelFile> {
    try {
      const file = await this.selectExcelFile();
      const validationResult = this.validateExcelFile(file);

      if (!validationResult.isValid) {
        return this.createResponse(false, validationResult.errorMessage!);
      }

      const [processedData, formData] = await Promise.all([
        this.processExcelFile(file),
        this.createFormData(file),
      ]);

      return this.createResponse(
        true,
        null,
        file.name,
        processedData,
        formData
      );
    } catch (error) {
      return this.handleError(error);
    }
  }

  private async selectExcelFile(): Promise<File> {
    return new Promise((resolve, reject) => {
      const input = this.createFileInput();
      let fileHandled = false;

      const cleanup = () => {
        window.removeEventListener('focus', handleCancel);
        document.body.removeChild(input);
      };

      const handleCancel = () => {
        setTimeout(() => {
          if (!fileHandled) {
            cleanup();
            reject(new Error('تم إلغاء اختيار الملف'));
          }
        }, 500);
      };

      input.addEventListener('change', (event) => {
        fileHandled = true;
        cleanup();

        const file = (event.target as HTMLInputElement).files?.[0];
        file ? resolve(file) : reject(new Error('لم يتم تحديد أي ملف'));
      });

      window.addEventListener('focus', handleCancel);
      document.body.appendChild(input);
      input.click();
    });
  }

  private createFileInput(): HTMLInputElement {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = this.allowedExtensions.map(ext => `.${ext}`).join(', ');
    input.style.display = 'none';
    return input;
  }

  private validateExcelFile(file: File): { isValid: boolean; errorMessage?: string } {
    const extension = file.name.split('.').pop()?.toLowerCase();
    const isValidExtension = extension && this.allowedExtensions.includes(extension);
    const isValidMimeType = this.allowedMimeTypes.includes(file.type);

    if (!isValidExtension || !isValidMimeType) {
      return {
        isValid: false,
        errorMessage: 'تنسيق الملف غير صالح. يرجى تحميل ملف Excel (.xlsx, .xls)'
      };
    }

    return { isValid: true };
  }

  private async processExcelFile(file: File): Promise<any[]> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = (event) => {
        try {
          const data = new Uint8Array(event.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          resolve(this.workbookToJson(workbook));
        } catch (error) {
          reject(new Error('خطأ في معالجة ملف Excel'));
        }
      };

      reader.onerror = () => reject(new Error('خطأ في قراءة الملف'));
      reader.readAsArrayBuffer(file);
    });
  }

  private createFormData(file: File): FormData {
    const formData = new FormData();
    formData.append('file', file, file.name);
    formData.append('uploadDate', new Date().toISOString());
    return formData;
  }

  private workbookToJson(workbook: XLSX.WorkBook): any[] {
    return workbook.SheetNames.map((sheetName) => ({
      sheetName,
      data: XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], { header: 1 }),
    }));
  }

  private createResponse(
    isSuccess: boolean,
    errorMessage: string | null = null,
    fileName: string | null = null,
    result: any[] | null = null,
    formData?: FormData
  ): UploadExcelFile {
    return { isSuccess, errorMessage, fileName, result, formData };
  }

  private handleError(error: unknown): UploadExcelFile {
    const errorMessage = error instanceof Error ? error.message : 'حدث خطأ غير معروف';
    return this.createResponse(false, errorMessage);
  }

}
